import{_ as W,o as r,c as o,j as i,t as n,ae as V,af as U,F as S,B as g,N as h,e as p,E as O,w as G,Z as Q,b as j,H as X,n as P,T as $,h as M,p as K,ag as Z}from"./chunks/framework.05qZ2-8C.js";const q=[{id:"generation",label:"Skill 生成",label_en:"Generation",color:"#FF6B6B",technologies:[{id:"skill-creator",name:"Skill Creator",description:"Anthropic 官方在 Claude 文档中的 Agent Skills 创建指引（含 description 优化与 Eval 流程）",source:"Anthropic 官方",link:"https://docs.claude.com/en/docs/agents-and-tools/agent-skills",detail:{tagline:'Anthropic 官方在 Claude 文档中为 Agent Skills 提供的创建指引，把"写 Skill"变成"写测试 prompt → 跑 Eval → 看通过率 → 改 description → 再跑"的工程循环。',principle:'把传统"凭感觉写 Skill"变成可量化的工程循环：通过结构化问答引导式拆解需求，而非面对空白 SKILL.md；让作者写 10+ 个测试 prompt 形成测试 prompt + Eval 闭环，批量运行并可视化通过率；通过 description 自动优化器调整措辞提升 Skill 触发命中率，类似 SEO 标题优化。核心创新是把 Skill 当作"可被测试的软件构件"而非自然语言文档，并引入 description-as-trigger 概念，让生成阶段就关注路由可见性。',capabilities:["引导式 Skill 起草","批量 Eval 与通过率可视化","description 自动 A/B 优化"],limitations:["EvoSkills 对比显示 Skill Creator 基线通过率仅 34.1%，人工引导式创建存在天花板",'不支持从执行失败中自动发现新 Skill——作者必须先"知道要创建什么 Skill"',"紧密绑定 Claude Code / Anthropic 生态"],references:[{label:"Anthropic Agent Skills 官方文档",url:"https://docs.claude.com/en/docs/agents-and-tools/agent-skills"},{label:"EvoSkills 论文（Skill Creator 34.1% vs EvoSkills 75% 对比基线）",url:"https://arxiv.org/abs/2604.01687"}]},logo:"https://www.google.com/s2/favicons?domain=anthropic.com&sz=128"},{id:"skill-seekers",name:"Skill Seekers",description:"18 种数据源 → 20 个目标（12 LLM + 8 RAG / 向量）的自动化文档转 Skill 流水线（13.4K+ ★）",source:"社区开源 (13.4K+ ★)",link:"https://github.com/yusufkaraaslan/Skill_Seekers",detail:{tagline:'把 18 种数据源 → 20 个目标平台的"文档转 Skill"过程自动化的社区开源工具链。',principle:'把"喂入一个 API 文档 URL → 半天后输出一个高质量 SKILL.md"这条链路工程化：支持网页 / GitHub 仓库 / PDF / Jupyter Notebook / 视频 / 项目文档等 18 种数据源解析；通过 AI 增强 SKILL.md，初始转化质量 3/10 提升到增强后 9/10（清晰触发条件、分步指令、示例）；将 Skill 输出为 Claude / Gemini / OpenAI / Cursor / LangChain 等 20 个平台格式；创建新 Skill 时自动检查是否与已有 Skill 重叠。是业界唯一做到多平台 Skill 格式适配的产品，并把"AI 增强"内置为生成管线一步而非事后。',capabilities:["18 数据源解析（含 PDF / 视频 / Notebook）","跨 20 平台 Skill 格式转换","内置功能重叠检测"],limitations:['隐性知识盲区——只能从已有文档转化，无法捕获"从未被写进文档"的调试技巧','格式转换不验证"转换后在目标平台的行为等价性"，只保证语法合规',"图片中的流程图 / 架构图无法被解析为 Skill 逻辑"],references:[{label:"GitHub - Skill_Seekers",url:"https://github.com/yusufkaraaslan/Skill_Seekers"}]},logo:"https://raw.githubusercontent.com/yusufkaraaslan/Skill_Seekers/main/docs/assets/logo.png",metrics:{stars:13449,forks:1389,repo:"yusufkaraaslan/Skill_Seekers"}},{id:"evoskill",name:"EvoSkill",description:"Executor / Proposer / Skill-Builder 三 Agent 从失败中自动发现 Skill；+7.3% OfficeQA / +12.1% SealQA",source:"Sentient AGI (726 ★)",link:"https://github.com/sentient-agi/EvoSkill",detail:{tagline:'三 Agent 协作（Executor / Proposer / Skill-Builder）从失败轨迹中自动诊断"卡在哪"并物化为 Skill。',principle:'不依赖人类作者，从失败循环中自动生长 Skill：Executor 执行任务并记录轨迹；Proposer 分析失败轨迹诊断根因（如"Agent 不知道要等 DOM 稳定再抽取"）；Skill-Builder 将诊断结果物化为结构化 Skill 文件夹。关键机制是 Pareto 前沿选择 + Git 管理——每个变体在验证集上跑分，只有所有维度都不被超越的才保留，每个变体存为独立 Git 分支。在 OfficeQA 上 +7.3%、SealQA 上 +12.1%。',capabilities:["自动失败归因","Pareto 多维选择","Skill 进化历史可追溯"],limitations:['依赖 ground-truth 信号（必须知道"对了还是错了"才能诊断）',"在开放式任务（没有明确成功标准）上受限","主要在 OfficeQA / SealQA 基准上验证"],references:[{label:"EvoSkill 论文",url:"https://arxiv.org/abs/2603.02766"},{label:"GitHub - sentient-agi/EvoSkill",url:"https://github.com/sentient-agi/EvoSkill"}]},logo:"https://raw.githubusercontent.com/sentient-agi/EvoSkill/main/assets/evoskill_logo.png",metrics:{stars:730,forks:79,repo:"sentient-agi/EvoSkill",paperDate:"2026-03"}},{id:"evoskills",name:"EvoSkills / CoEvoSkills",description:"Surrogate Verifier + Ground-truth Oracle 协同进化（75% 通过率 vs Skill Creator 34.1% 基线）",source:"学术研究",link:"https://arxiv.org/abs/2604.01687",detail:{tagline:"协同进化 + 两层验证架构（Surrogate Verifier + Ground-truth Oracle），自生成 Skill 通过率 75% vs Skill Creator 基线 34.1%。",principle:"采用两层验证：Surrogate Verifier 是信息隔离的独立 LLM 会话，主动生成测试断言 + 结构化失败诊断，反馈密集但可能不准确；Ground-truth Oracle 在全新环境中重新执行 Skill，反馈稀疏但准确（不透明 pass/fail）。消融实验显示去掉 Surrogate Verifier 通过率从 71.1% 暴跌至 41.1%。协同进化驱动方法论级创新而非仅调参——例如系外行星周期检测中 Generator 从 BLS 切换到 TLS + 两阶段搜索达到 100% 通过率。Claude Opus 4.6 上进化的 Skill 跨 6 个模型迁移均获得 +36-44pp 提升。",capabilities:["Surrogate Verifier + Oracle 两层验证","协同进化驱动方法论级创新","跨模型迁移有效（+36-44pp）"],limitations:["并未真正去掉 ground-truth——Surrogate 降低对人工验证依赖，但 oracle 层仍需正确性判断","Surrogate 的判断力上限 = LLM 自身领域知识，对运维 / 医疗 / 法律等深度领域可能无法生成有效断言","仍有 25% 失败","计算成本较高（多轮迭代 × 多次验证）"],references:[{label:"EvoSkills 论文",url:"https://arxiv.org/abs/2604.01687"},{label:"GitHub - CoEvoSkills",url:"https://github.com/Zhang-Henry/CoEvoSkills"},{label:"官网 evoskills.net",url:"https://evoskills.net/"}]},metrics:{stars:21,forks:1,repo:"Zhang-Henry/CoEvoSkills",paperDate:"2026-04"}},{id:"claudeception",name:"Claudeception",description:"Claude Code 会话中自动提取「可复用 + 非平凡 + 具体 + 已验证」的 Skill（2.3K+ ★）",source:"社区开源 (2.3K+ ★)",link:"https://github.com/blader/Claudeception",detail:{tagline:'在 Claude Code 每次会话中，通过 Hook 机制自动评估并提取"值得记住"的 Skill ——让 Agent 不再每天失忆。',principle:'四条件 Skill 提取：不是什么都记，只提取满足可复用（不只对当前项目有用）、非平凡（不是查文档就能知道的，间接过滤模型已知知识）、具体（能描述精确的触发条件）、已验证（实际生效过）四条件的知识，每个会话通常只提取 1-3 个 Skill。语义精准的 description——不写"帮助解决数据库问题"，而写"Fix for PrismaClientKnownRequestError in serverless environment with connection pool exhaustion"，下次遇到同样错误信息时 Skill 能被精准召回。典型场景：调试 Next.js getServerSideProps 在 Edge Runtime 下不可用，提取触发条件 + 解法 + 验证状态。',capabilities:["Hook 机制自动评估并提取 Skill","四条件过滤（可复用 / 非平凡 / 具体 / 已验证）","语义精准 description 精准召回"],limitations:["仅面向 Claude Code 平台","Skill 不跨用户共享（vs SkillClaw / OpenSpace 的集体学习模式）","提取质量依赖 LLM 自身判断，无外部验证","无公开的定量评测数据"],references:[{label:"GitHub - blader/Claudeception",url:"https://github.com/blader/Claudeception"}]},metrics:{stars:2322,forks:22,repo:"blader/Claudeception"}},{id:"trace2skill",name:"Trace2Skill",description:"并行多 sub-agent 编队从轨迹池蒸馏 Skill；35B 模型在 WikiTableQuestions 上 +57.65pp 超 122B",source:"阿里 Qwen + ETH Zurich",link:"https://arxiv.org/abs/2603.25158",detail:{tagline:"并行多 sub-agent 编队从轨迹池蒸馏 Skill——整体归纳，避免逐条轨迹过拟合。35B 模型 +57.65pp 超越 122B。",principle:'并行多 Agent 分析不是一条条轨迹顺序处理，而是同时派出一支 sub-agent 编队并行分析整个轨迹池，分两组：成功分析师问"这些做对的案例有什么共同点"，错误分析师问"这些做错的案例卡在哪"，每组独立提出 Skill 补丁建议。层级合并 + 程序化冲突检测：所有补丁不是简单拼接，而是通过层级归纳推理合并为无冲突的 Skill 目录——例如分析师 A 建议"遇到 timeout 时重试 3 次"，分析师 B 建议"切换备用 API"，合并器识别冲突选择支持证据更多的方案，或组合为"先重试 3 次，仍失败则切换"。35B 模型 + Trace2Skill 在 WikiTableQuestions 上超越 122B agent +57.65pp。',capabilities:["并行轨迹分析，规模化","程序化冲突检测 + 格式验证","跨模型迁移有效"],limitations:["需要大量并行执行轨迹作为输入，冷启动场景受限",'合并阶段在"信号部分相关或存在领域偏差"时的行为尚不清楚',"蒸馏出的 Skill 可解释性较差——人很难读懂 LLM 写给自己的 Skill"],references:[{label:"Trace2Skill 论文",url:"https://arxiv.org/abs/2603.25158"}]},metrics:{paperDate:"2026-03"}},{id:"skillforge-gen",name:"SkillForge",description:"从历史工单（1,883 条）挖掘领域工具 schema + 三阶段自优化流水线（SIGIR 2026 Industry）",source:"工业研究 (SIGIR 2026)",link:"https://arxiv.org/abs/2604.08618",detail:{tagline:"工业研究的领域专属 Skill 自动化生产线——从 1,883 条历史工单挖掘工具 schema + 三阶段自优化流水线，5 个真实云技术支持场景验证（SIGIR 2026 Industry Track）。",principle:'Domain-Contextualized Skill Creator 从历史工单挖掘两类信息：工具挖掘识别专家在工单中高频使用的诊断工具提取其 schema；知识抽取从内部文档和工单引用的参考资料中提取领域规则（例如分析 1000 个"ECS 无法启动"工单发现专家 90% 时间先跑 ecs-diag → 再查 VPC 安全组 → 最后看系统日志，这个诊断路径编码为 Skill）。三阶段自优化流水线（关键创新）：Failure Analyzer 分析执行失败；Skill Diagnostician 将失败追溯到具体 Skill 缺陷；Skill Optimizer 重写 Skill 消除根因——直接将失败归因到 Skill。5 个真实云技术支持场景使用 1,883 条匿名化生产工单 + 3,737 任务验证。',capabilities:["Domain-Contextualized Skill Creator 从工单挖掘工具 + 知识","Failure Analyzer / Diagnostician / Optimizer 三阶段流水线","归因分离直接定位 Skill 缺陷"],limitations:["仅在云技术支持场景验证，通用性未知","代码和数据未开源（企业隐私）","聚焦单 Skill 优化，不涉及多 Skill 协同",'Diagnostician 只做"是否 Skill 的问题"这一层归因，不区分 Skill 内容 / 模型能力 / 路由错误'],references:[{label:"SkillForge 论文",url:"https://arxiv.org/abs/2604.08618"}]},metrics:{paperDate:"2026-04",venue:"SIGIR 2026"}},{id:"skillx",name:"SkillX",description:"策略 / 功能 / 原子三层 Skill 粒度设计（AppWorld + BFCL-v3 + τ²-Bench 验证）",source:"学术研究",link:"https://arxiv.org/abs/2604.04804",detail:{tagline:"把 Skill 显式分为策略层 / 功能层 / 原子层三层粒度，强模型经验向弱模型蒸馏。",principle:'三层 Skill 设计：策略层做高层规划（"先认证再操作"）、功能层定具体步骤（"用 OAuth2 获取 Token"）、原子层是最小操作单元（"发送 POST 请求"）。像乐高积木，底座不同但上面的结构件通用，上层 Skill 跨 Agent 复用，底层 Skill 适配不同环境。强模型蒸馏给弱模型：GPT-4 级别积累的 Skill 经验可被 GPT-3.5 级别直接消费，AppWorld / τ²-Bench 上弱模型获得显著提升。解决"团队各自重复发明轮子"——一个团队的经验沉淀为可复用三层 Skill 给其他团队用。',capabilities:["三层 Skill 粒度自动划分","跨模型蒸馏","跨团队 Skill 复用"],limitations:["跨环境迁移需要底层工具集相对稳定，若两个环境的 API 完全不同上层 Skill 也难复用",'没有自动化工具判断"当前 Skill 是太抽象了还是太具体了"——三层粒度是设计准则而非自动决策',"学术阶段，未产品化"],references:[{label:"SkillX 论文",url:"https://arxiv.org/abs/2604.04804"}]},metrics:{paperDate:"2026-04"}},{id:"skillrl",name:"SkillRL",description:"经验蒸馏 + 自适应检索 + Skill 库与 RL 策略递归共进化的分层 SkillBank（+15.3% over baselines）",source:"aiming-lab (学术)",link:"https://arxiv.org/abs/2602.08234",detail:{tagline:"通过经验蒸馏 + 自适应检索 + 递归共进化，让分层 SkillBank 与 RL 策略一起生长。+15.3% over baselines（ALFWorld / WebShop / 7 搜索增强任务）。",principle:"三个关键创新：经验蒸馏机制把 Agent 的成功 / 失败经验提炼为分层 SkillBank（策略层 / 操作层）；自适应检索策略同时支持通用启发式和任务特定的 Skill 召回；递归共进化机制让 Skill 库不是静态的，而是随 RL 策略一起更新——新策略发现的新模式回写为 Skill，新 Skill 又改进下次策略。在 ALFWorld、WebShop 和 7 个搜索增强任务上 +15.3%。与 EvoSkill 区别：EvoSkill 是纯 LLM-based 从失败中发现 Skill，SkillRL 是 RL-based 让 Skill 库与 RL policy 同时学习。",capabilities:["分层 SkillBank 构建","自适应 Skill 检索","与 RL 策略的递归共进化"],limitations:["需要可定义 reward 的环境，开放式任务受限","13 位作者均为学术研究，未见生产部署","RL 训练成本高于纯 LLM 路径"],references:[{label:"SkillRL 论文",url:"https://arxiv.org/abs/2602.08234"},{label:"GitHub - aiming-lab/SkillRL",url:"https://github.com/aiming-lab/SkillRL"}]},metrics:{stars:720,forks:55,repo:"aiming-lab/SkillRL",paperDate:"2026-02"}}]},{id:"recall",label:"Skill 召回",label_en:"Recall / Routing",color:"#4ECDC4",technologies:[{id:"skillrouter",name:"SkillRouter",description:"全文检索 + 重排，80K Skill 池 74% Hit@1；1.2B 参数比 16B 基线少 13×、快 5.8×",source:"学术研究",link:"https://arxiv.org/abs/2603.22455",detail:{tagline:'在 80K Skill 池上证明"全文检索是不可绕过的必要条件"——1.2B 模型比 16B 基线少 13× 参数、快 5.8×，端到端 Hit@1 74%。',principle:'两阶段检索 - 重排架构：双编码器检索粗排用 Qwen3-Emb-0.6B 把查询与全量 Skill 向量化检索 Top-20 候选；交叉编码器重排细排用 SR-Rank-0.6B 通过交叉注意力做精细化相关性打分。推翻"标题+简介够用"的设计假设——在 ~80K Skill 池上隐藏 Skill body 后路由准确率暴跌 31-44 个百分点。紧凑高效：1.2B 总参数量 vs 16B Qwen3 基线，参数量减少 13×、推理速度快 5.8×。在 Kimi-K2.5、GLM-5、Claude Sonnet/Opus 4.6 四 Agent 端到端验证，路由准确率提升转化为最终任务成功率提升。',capabilities:["双编码器 + 交叉编码器两阶段检索","1.2B 紧凑模型部署可在消费级硬件","端到端 Hit@1 74%，重排修复 12.7% 检索失败"],limitations:["74% Hit@1 意味着仍有 26% 首选路由错误",'只做单次"选哪个 Skill"决策，不涉及多 Skill 动态编排','识别出"相似 Skill"后没有方案做自动合并'],references:[{label:"SkillRouter 论文",url:"https://arxiv.org/abs/2603.22455"},{label:"GitHub - zhengyanzhao1997/SkillRouter",url:"https://github.com/zhengyanzhao1997/SkillRouter"}]},metrics:{stars:107,forks:7,repo:"zhengyanzhao1997/SkillRouter",paperDate:"2026-03"}},{id:"agentskillos-recall",name:"AgentSkillOS",description:"Capability Tree 递归分类 + DAG 编排，200–200K 规模逼近理想准确率",source:"学术研究",link:"https://arxiv.org/abs/2603.02176",detail:{tagline:'把数十万 Skill 组织成 Capability Tree + DAG 编排的"操作系统级"基础设施。',principle:'Capability Tree 递归分类把数十万 Skill 组织成一棵能力树：节点是能力类别，叶子是具体 Skill，用户提任务时系统从树根递归定位到最相关 Skill 子集；对比线性搜索，树状检索在 200 - 200K 规模上都接近理想准确率。DAG 编排（核心创新）识别任务中的 Skill 依赖关系构建有向无环图：能并行的步骤并行（如"抓取数据" + "准备 PPT 模板"），必须串行的按序执行，DAG 执行显著优于简单逐个调用。基准覆盖数据计算 / 文档创建 / 动态视频 / 视觉设计 / Web 交互 30 个任务。',capabilities:["Capability Tree 树状 Skill 检索","DAG 任务编排与并行执行","200-200K 规模接近理想检索准确率"],limitations:["DAG 编排假设 Skill 依赖关系可在执行前静态确定，动态依赖场景（第二步选择取决于第一步结果）未覆盖","不涉及 Skill 进化或安全治理","仅学术验证，未产品化"],references:[{label:"AgentSkillOS 论文",url:"https://arxiv.org/abs/2603.02176"}]},metrics:{paperDate:"2026-03"}},{id:"skillnet-recall",name:"SkillNet",description:"200K+ Skill 共享仓库 + 三层 Ontology（分类 / 实体 / 关系图谱），ALFWorld/WebShop/ScienceWorld +40% reward",source:"浙大 NLP (735 ★)",link:"https://github.com/zjunlp/SkillNet",detail:{tagline:"把 200K+ Skill 生态组织成「应用商店基础设施」—— Ontology 三层架构 + 5 维质量评分（GitHub 735 星）。",principle:'把"Skill 生态"从无组织的 200K+ 个孤岛升级为可治理的知识图谱：Skill Ontology 三层架构——领域分类（如"数据处理""代码生成"）→ Skill 实体（200K+）→ 关系图谱（功能重叠 / 依赖 / 升级版）；5 维质量评分覆盖安全 / 完整 / 可执行 / 可维护 / 成本，超越 Star 数；在 ALFWorld / WebShop / ScienceWorld 三环境实证 +40% reward、-30% 执行步骤。业界首个面向 Skill 生态的关系治理框架，并把"Skill 内在质量"标准化。',capabilities:["Skill 自动分类、查重、关系建模","多维质量评分","在线开放知识库"],limitations:['5 维评分评估的是"Skill 写得好不好"，不是"在你的场景有没有效"',"团队自述：动态组合和跨领域迁移仍具挑战性","关系图谱能识别重叠但不执行自动合并"],references:[{label:"SkillNet 论文",url:"https://arxiv.org/abs/2603.04448"},{label:"GitHub - zjunlp/SkillNet",url:"https://github.com/zjunlp/SkillNet"},{label:"在线知识库 skillnet.openkg.cn",url:"http://skillnet.openkg.cn/"},{label:"HuggingFace 博客",url:"https://huggingface.co/blog/xzwnlp/skillnet"}]},logo:"https://raw.githubusercontent.com/zjunlp/SkillNet/main/images/skillnet.png",metrics:{stars:738,forks:72,repo:"zjunlp/SkillNet",paperDate:"2026-03"}},{id:"skillrouter-org",name:"SkillRouter.org",description:"MCP 路由商业服务（当前为早期阶段 / 落地页，技术细节未公开）",source:"商业产品（早期）",link:"https://skillrouter.org/",detail:{tagline:"早期阶段的 MCP 路由商业服务（当前主要为落地页 / 营销页，未见公开评测与生产用户案例）。",principle:'提供 MCP Server 即插即用接入 Claude Code / Cursor 等，声称"生态级学习优化推荐精度"。注意：SkillRouter.org（社区商业产品）与学术论文 SkillRouter（arXiv 2603.22455）名称相近但不是同一项工作——前者是商业服务，技术细节不透明；后者是论文 + 开源实现。',capabilities:["MCP Server 即插即用","声称生态级学习优化推荐精度"],limitations:["技术细节不透明——路由算法、模型规模、训练数据均未公开","无公开评测数据——与 SkillRouter 学术工作的 74% Hit@1 不可直接对比","商业化产品，可能存在 vendor lock-in"],references:[{label:"skillrouter.org 官网",url:"https://skillrouter.org/"},{label:"学术工作（不同项目）SkillRouter 论文",url:"https://arxiv.org/abs/2603.22455"}]},logo:"https://www.google.com/s2/favicons?domain=skillrouter.org&sz=128"}]},{id:"execution",label:"Skill 执行",label_en:"Execution",color:"#45B7D1",technologies:[{id:"openspace-exec",name:"OpenSpace",description:"作为 MCP Server 即插即用接入 Claude Code / Codex / Cursor（6.1K+ ★）",source:"HKU HKUDS (6.1K+ ★)",link:"https://github.com/HKUDS/OpenSpace",detail:{tagline:"把 Skill 全生命周期管理整合到一个 MCP Server 里——三模式自动进化（FIX / DERIVED / CAPTURED）+ 6.1K+ 星生态。",principle:'三种进化模式：FIX 在 Skill 执行报错时自动诊断 + 生成修复补丁 + 验证 + 更新；DERIVED 发现用户模式重复（如"CSV 转 Excel"后总跟着表头格式化）自动派生新 Skill；CAPTURED 检测可复用模式（Agent 反复"先备份 → 修改 → 验证"）提取为新 Skill。以 MCP Server 即插即用接入 Claude Code / Codex / Cursor 不改 Agent 代码，暴露 execute_task / search_skills / fix_skill / upload_skill 四个工具。220 个真实任务质量 40.8% → 70.8%，Token 减少 46%；零人工代码 Showcase 从 6 个初始 Skill 自动进化出 60+ 个 Skill。',capabilities:["FIX / DERIVED / CAPTURED 三模式自动进化","MCP Server 即插即用接入主流 Agent","220 任务质量 40.8%→70.8%，Token 减少 46%"],limitations:["安全审计和权限控制未详述","主要在 Qwen 3.5+ 上验证","长期进化稳定性未充分验证"],references:[{label:"GitHub - HKUDS/OpenSpace",url:"https://github.com/HKUDS/OpenSpace"},{label:"社区云 open-space.cloud",url:"https://open-space.cloud/"}]},logo:"https://raw.githubusercontent.com/HKUDS/OpenSpace/main/assets/logo.png",metrics:{stars:6125,forks:759,repo:"HKUDS/OpenSpace"}},{id:"agentskillos-exec",name:"AgentSkillOS",description:"DAG 编排：能并行的并行、必须串行的串行（30 任务 5 类基准）",source:"学术研究",link:"https://arxiv.org/abs/2603.02176",detail:{tagline:'把数十万 Skill 组织成 Capability Tree + DAG 编排的"操作系统级"基础设施。',principle:'Capability Tree 递归分类把数十万 Skill 组织成一棵能力树：节点是能力类别，叶子是具体 Skill，用户提任务时系统从树根递归定位到最相关 Skill 子集；对比线性搜索，树状检索在 200 - 200K 规模上都接近理想准确率。DAG 编排（核心创新）识别任务中的 Skill 依赖关系构建有向无环图：能并行的步骤并行（如"抓取数据" + "准备 PPT 模板"），必须串行的按序执行，DAG 执行显著优于简单逐个调用。基准覆盖数据计算 / 文档创建 / 动态视频 / 视觉设计 / Web 交互 30 个任务。',capabilities:["Capability Tree 树状 Skill 检索","DAG 任务编排与并行执行","200-200K 规模接近理想检索准确率"],limitations:["DAG 编排假设 Skill 依赖关系可在执行前静态确定，动态依赖场景（第二步选择取决于第一步结果）未覆盖","不涉及 Skill 进化或安全治理","仅学术验证，未产品化"],references:[{label:"AgentSkillOS 论文",url:"https://arxiv.org/abs/2603.02176"}]},metrics:{paperDate:"2026-03"}},{id:"memento-skills",name:"Memento-Skills",description:"Read → Execute → Reflect → Write 闭环 + 行为可训练 Skill Router（GAIA +26.2%, HLE +116.2%）",source:"学术研究 (1.4K+ ★)",link:"https://github.com/Memento-Teams/Memento-Skills",detail:{tagline:'让 Agent 拥有"长期记忆"—— Read → Execute → Reflect → Write 闭环 + 行为可训练 Skill Router。GAIA +26.2%、HLE +116.2%。',principle:'Read → Execute → Reflect → Write 闭环：Read 从 Skill 库检索相关经验，Execute 执行任务，Reflect 反思"这次做得好不好，可以改进什么"，Write 将反思结果更新回 Skill 库。像一个会写工作日志的员工，每天下班前总结经验，第二天先翻日志再开始工作。行为可训练 Skill Router 不只是关键词匹配，而是根据当前上下文状态学习"什么情况下应该用什么 Skill"。GAIA 基准 +26.2%，HLE 基准 +116.2%。',capabilities:["长期记忆持久化","反思驱动 Skill 自更新","上下文敏感的 Skill 路由"],limitations:["学术研究导向，产品化和易用性不如 OpenSpace、Hermes 等工程项目","反思质量依赖 LLM 自身判断"],references:[{label:"Memento-Skills 论文",url:"https://arxiv.org/abs/2603.18743"},{label:"GitHub - Memento-Teams/Memento-Skills",url:"https://github.com/Memento-Teams/Memento-Skills"}]},metrics:{stars:1367,forks:154,repo:"Memento-Teams/Memento-Skills",paperDate:"2026-03"}},{id:"skcc",name:"SkCC",description:"SkIR 强类型 IR：将 Skill 语义与框架格式解耦，实现跨 Agent 框架可移植部署",source:"学术研究",link:"https://arxiv.org/abs/2605.03353",detail:{tagline:"跨框架 Skill 编译——引入 SkIR 强类型 IR 把 Skill 语义与 Agent 框架格式解耦，让一份 Skill 在 Claude Code / Kimi CLI 等不同框架间可移植部署。",principle:'借鉴传统编译器思路，SkIR 是强类型中间表示：Skill 用强类型 IR 表达（与具体 Agent 框架解耦），通过 codegen 编译为各框架的原生格式（Claude Code / Kimi CLI / Cursor 等）。关键数字：Claude Code 接入 SkCC 前 21.1% → 接入后 33.3%；Kimi CLI 接入前 35.1% → 接入后 48.7%。这是业界第一个直接解决"Skill 在不同 Agent 框架上行为不一致"问题的系统方案——同一个 Skill 在 Claude Code 和 OpenCode 上即使格式兼容，执行行为也可能完全不同，SkCC 通过强类型 IR 解决这个问题。',capabilities:["Skill IR 强类型抽象","跨框架自动 codegen","包含安全性考虑"],limitations:["学术阶段，未见生产部署","需要各框架开发对应 codegen target","不解决 Skill 内容本身的质量问题"],references:[{label:"SkCC 论文",url:"https://arxiv.org/abs/2605.03353"}]},metrics:{paperDate:"2026-05"}}]},{id:"evaluation",label:"Skill 评测",label_en:"Evaluation",color:"#96CEB4",technologies:[{id:"skillsbench",name:"SkillsBench",description:"7,308 条标准化轨迹 / 84 任务 / 11 领域（leaderboard 标注 86），Skill 评测事实标准（+16.2pp）",source:"学术研究 (1.2K+ ★)",link:"https://github.com/benchflow-ai/skillsbench",detail:{tagline:'第一个把 Skill 本身作为评测对象的标准化基准—— 7,308 条轨迹 / 84 任务 / 11 领域，揭示"加 Skill 反而更差"等反共识结论。',principle:"三条件对比设计像药物试验的安慰剂对照组：同一任务在不用 Skill / 用精心编写的 Skill / 用 Agent 自己生成的 Skill 三种条件下跑。关键发现：精心编写的 Skill 显著有效平均 +16.2pp，但领域差异巨大（软件工程仅 +4.5pp，医疗 +51.9pp，差了 10×）；自生成 Skill 平均无增益（学生自己写复习笔记帮不了自己）；部分场景 Skill 有害（84 任务中 16 个负增益，加了反而更差）；聚焦优于全面（2-3 模块精简 Skill 优于长篇文档）。第一次量化了 Skill 生态中最重要的反共识事实。",capabilities:["三条件对比的严谨评测设计","11 领域 / 84 任务 / 7308 轨迹覆盖","事实标准，被后续工作引用为基线"],limitations:["只做 pass/fail 结果评测，不追踪 Agent 是否实际遵从了 Skill 流程","无法解释 16 个负增益案例的根因（Agent 忽略？Skill 有缺陷？路由选错？）","84 个确定性验证器都是手工编写，覆盖 11 个领域，但 SkillNet 上有 200K+ Skill 横跨数百领域，绝大多数没有评测基础设施"],references:[{label:"SkillsBench 论文",url:"https://arxiv.org/abs/2602.12670"},{label:"GitHub - benchflow-ai/skillsbench",url:"https://github.com/benchflow-ai/skillsbench"},{label:"官网 skillsbench.ai",url:"https://www.skillsbench.ai/"}]},metrics:{stars:1159,forks:291,repo:"benchflow-ai/skillsbench",paperDate:"2026-02"}},{id:"skillnet-eval",name:"SkillNet (5 维评分)",description:"安全 / 完整 / 可执行 / 可维护 / 成本五维 Skill 内在质量评估",source:"浙大 NLP",link:"https://arxiv.org/abs/2603.04448",detail:{tagline:"把 200K+ Skill 生态组织成「应用商店基础设施」—— Ontology 三层架构 + 5 维质量评分（GitHub 735 星）。",principle:'把"Skill 生态"从无组织的 200K+ 个孤岛升级为可治理的知识图谱：Skill Ontology 三层架构——领域分类（如"数据处理""代码生成"）→ Skill 实体（200K+）→ 关系图谱（功能重叠 / 依赖 / 升级版）；5 维质量评分覆盖安全 / 完整 / 可执行 / 可维护 / 成本，超越 Star 数；在 ALFWorld / WebShop / ScienceWorld 三环境实证 +40% reward、-30% 执行步骤。业界首个面向 Skill 生态的关系治理框架，并把"Skill 内在质量"标准化。',capabilities:["Skill 自动分类、查重、关系建模","多维质量评分","在线开放知识库"],limitations:['5 维评分评估的是"Skill 写得好不好"，不是"在你的场景有没有效"',"团队自述：动态组合和跨领域迁移仍具挑战性","关系图谱能识别重叠但不执行自动合并"],references:[{label:"SkillNet 论文",url:"https://arxiv.org/abs/2603.04448"},{label:"GitHub - zjunlp/SkillNet",url:"https://github.com/zjunlp/SkillNet"},{label:"在线知识库 skillnet.openkg.cn",url:"http://skillnet.openkg.cn/"},{label:"HuggingFace 博客",url:"https://huggingface.co/blog/xzwnlp/skillnet"}]},logo:"https://raw.githubusercontent.com/zjunlp/SkillNet/main/images/skillnet.png",metrics:{stars:738,forks:72,repo:"zjunlp/SkillNet",paperDate:"2026-03"}},{id:"evoskills-eval",name:"EvoSkills (Surrogate Verifier)",description:"信息隔离的 LLM 主动生成测试断言 + 失败诊断反馈；去掉 Surrogate 通过率 71.1% → 41.1%",source:"学术研究",link:"https://arxiv.org/abs/2604.01687",detail:{tagline:"协同进化 + 两层验证架构（Surrogate Verifier + Ground-truth Oracle），自生成 Skill 通过率 75% vs Skill Creator 基线 34.1%。",principle:"采用两层验证：Surrogate Verifier 是信息隔离的独立 LLM 会话，主动生成测试断言 + 结构化失败诊断，反馈密集但可能不准确；Ground-truth Oracle 在全新环境中重新执行 Skill，反馈稀疏但准确（不透明 pass/fail）。消融实验显示去掉 Surrogate Verifier 通过率从 71.1% 暴跌至 41.1%。协同进化驱动方法论级创新而非仅调参——例如系外行星周期检测中 Generator 从 BLS 切换到 TLS + 两阶段搜索达到 100% 通过率。Claude Opus 4.6 上进化的 Skill 跨 6 个模型迁移均获得 +36-44pp 提升。",capabilities:["Surrogate Verifier + Oracle 两层验证","协同进化驱动方法论级创新","跨模型迁移有效（+36-44pp）"],limitations:["并未真正去掉 ground-truth——Surrogate 降低对人工验证依赖，但 oracle 层仍需正确性判断","Surrogate 的判断力上限 = LLM 自身领域知识，对运维 / 医疗 / 法律等深度领域可能无法生成有效断言","仍有 25% 失败","计算成本较高（多轮迭代 × 多次验证）"],references:[{label:"EvoSkills 论文",url:"https://arxiv.org/abs/2604.01687"},{label:"GitHub - CoEvoSkills",url:"https://github.com/Zhang-Henry/CoEvoSkills"},{label:"官网 evoskills.net",url:"https://evoskills.net/"}]},metrics:{stars:21,forks:1,repo:"Zhang-Henry/CoEvoSkills",paperDate:"2026-04"}},{id:"skillforge-eval",name:"SkillForge (Diagnostician)",description:"Failure Analyzer → Skill Diagnostician：将执行失败追溯回具体 Skill 缺陷",source:"工业研究",link:"https://arxiv.org/abs/2604.08618",detail:{tagline:"工业研究的领域专属 Skill 自动化生产线——从 1,883 条历史工单挖掘工具 schema + 三阶段自优化流水线，5 个真实云技术支持场景验证（SIGIR 2026 Industry Track）。",principle:'Domain-Contextualized Skill Creator 从历史工单挖掘两类信息：工具挖掘识别专家在工单中高频使用的诊断工具提取其 schema；知识抽取从内部文档和工单引用的参考资料中提取领域规则（例如分析 1000 个"ECS 无法启动"工单发现专家 90% 时间先跑 ecs-diag → 再查 VPC 安全组 → 最后看系统日志，这个诊断路径编码为 Skill）。三阶段自优化流水线（关键创新）：Failure Analyzer 分析执行失败；Skill Diagnostician 将失败追溯到具体 Skill 缺陷；Skill Optimizer 重写 Skill 消除根因——直接将失败归因到 Skill。5 个真实云技术支持场景使用 1,883 条匿名化生产工单 + 3,737 任务验证。',capabilities:["Domain-Contextualized Skill Creator 从工单挖掘工具 + 知识","Failure Analyzer / Diagnostician / Optimizer 三阶段流水线","归因分离直接定位 Skill 缺陷"],limitations:["仅在云技术支持场景验证，通用性未知","代码和数据未开源（企业隐私）","聚焦单 Skill 优化，不涉及多 Skill 协同",'Diagnostician 只做"是否 Skill 的问题"这一层归因，不区分 Skill 内容 / 模型能力 / 路由错误'],references:[{label:"SkillForge 论文",url:"https://arxiv.org/abs/2604.08618"}]},metrics:{paperDate:"2026-04",venue:"SIGIR 2026"}},{id:"skillret",name:"SkillRet",description:"Skill 检索大规模基准：17,810 公共 Skill / 63K 训练 / 5K 评测查询，NDCG@10 +13.1",source:"学术研究",link:"https://arxiv.org/abs/2605.05726",detail:{tagline:"Skill 检索的大规模 benchmark —— 17,810 公共 Skill + 63K 训练 + 5K 评测查询。比最强基线 NDCG@10 +13.1，比最强 off-the-shelf 检索器 +16.9。",principle:'提供 Skill 检索领域当前最大规模的 benchmark：17,810 公共 Skill、63,259 训练样本、4,997 评测查询。比最强 prior retriever NDCG@10 +13.1，比最强 off-the-shelf retriever +16.9。与 SkillRouter 的关系互补：SkillRouter 提供路由方法论与轻量模型架构，SkillRet 提供 SkillRouter 缺失的标准化评测套件，两者搭配业界首次有了完整的"召回方法 + 召回评测"组合。',capabilities:["标准化 Skill 检索评测","17,810 Skill 的公共数据集","NDCG@10 等多种检索指标"],limitations:["数据集质量取决于 17K Skill 的来源覆盖","学术阶段，未见工业 retriever 提交","不评测路由后的 task success rate（只评测检索本身）"],references:[{label:"SkillRet 论文",url:"https://arxiv.org/abs/2605.05726"}]},metrics:{paperDate:"2026-05"}}]},{id:"optimization",label:"Skill 优化",label_en:"Optimization",color:"#DDA0DD",technologies:[{id:"openspace",name:"OpenSpace",description:"FIX / DERIVED / CAPTURED 三模式实时进化；220 任务 40.8% → 70.8%、Token -46%、6 → 60+ Skill",source:"HKU HKUDS (6.1K+ ★)",link:"https://github.com/HKUDS/OpenSpace",detail:{tagline:"把 Skill 全生命周期管理整合到一个 MCP Server 里——三模式自动进化（FIX / DERIVED / CAPTURED）+ 6.1K+ 星生态。",principle:'三种进化模式：FIX 在 Skill 执行报错时自动诊断 + 生成修复补丁 + 验证 + 更新；DERIVED 发现用户模式重复（如"CSV 转 Excel"后总跟着表头格式化）自动派生新 Skill；CAPTURED 检测可复用模式（Agent 反复"先备份 → 修改 → 验证"）提取为新 Skill。以 MCP Server 即插即用接入 Claude Code / Codex / Cursor 不改 Agent 代码，暴露 execute_task / search_skills / fix_skill / upload_skill 四个工具。220 个真实任务质量 40.8% → 70.8%，Token 减少 46%；零人工代码 Showcase 从 6 个初始 Skill 自动进化出 60+ 个 Skill。',capabilities:["FIX / DERIVED / CAPTURED 三模式自动进化","MCP Server 即插即用接入主流 Agent","220 任务质量 40.8%→70.8%，Token 减少 46%"],limitations:["安全审计和权限控制未详述","主要在 Qwen 3.5+ 上验证","长期进化稳定性未充分验证"],references:[{label:"GitHub - HKUDS/OpenSpace",url:"https://github.com/HKUDS/OpenSpace"},{label:"社区云 open-space.cloud",url:"https://open-space.cloud/"}]},logo:"https://raw.githubusercontent.com/HKUDS/OpenSpace/main/assets/logo.png",metrics:{stars:6125,forks:759,repo:"HKUDS/OpenSpace"}},{id:"hermes-self-evolution",name:"Hermes Self-Evolution",description:"GEPA 优化器 + 严格约束门控 + PR 模式人工审核（父仓 hermes-agent 145K+ ★）",source:"Nous Research (3.1K+ ★)",link:"https://github.com/NousResearch/hermes-agent-self-evolution",detail:{tagline:"Nous Research 的 Skill 自动进化引擎—— GEPA 优化器（ICLR 2026 接收）+ 严格约束门控 + PR 模式人工审核。",principle:'GEPA 优化器不是简单试错，而是读取执行轨迹理解"为什么失败"再提出针对性改进——例如 GitHub PR 代码审查 Skill 在大 PR 上遗漏安全问题，GEPA 分析轨迹发现"Skill 没有指示 Agent 按文件类型分组审查"，生成改进版本加上指示。基于 DSPy 框架，已被 ICLR 2026 接收。严格安全门控：每个进化变体必须通过完整测试套件，长度惩罚防止冗长漂移，最终以 PR 形式提交到 hermes-agent 仓库由人类审核。双数据源支持 synthetic 合成评测数据与 sessiondb 真实会话历史（兼容 Claude Code / Copilot / Hermes），无 GPU 依赖。',capabilities:["GEPA 优化器读取轨迹理解失败根因","严格约束门控 + PR 模式人工审核","双数据源：synthetic + sessiondb"],limitations:["紧密绑定 Hermes Agent 生态","进化结果需人工审核（PR 模式），非全自动部署","跨领域迁移未验证","测试套件本身不包含安全检查（约束门控只能拦截功能性退化）"],references:[{label:"hermes-agent-self-evolution GitHub",url:"https://github.com/NousResearch/hermes-agent-self-evolution"},{label:"Hermes Agent 主仓库",url:"https://github.com/NousResearch/hermes-agent"},{label:"TokenMix Review 评测",url:"https://tokenmix.ai/blog/hermes-agent-review-self-improving-open-source-2026"}]},metrics:{stars:3068,forks:332,repo:"NousResearch/hermes-agent-self-evolution",parentStars:145764,parentRepo:"NousResearch/hermes-agent",venue:"ICLR 2026"}},{id:"skillclaw",name:"SkillClaw",description:"后台守护进程聚合多用户轨迹 → 进化 Skill → 同步全用户（Qwen3-Max + WildClawBench 验证）",source:"AMAP-ML (1.3K+ ★)",link:"https://github.com/AMAP-ML/SkillClaw",detail:{tagline:"后台守护进程静默聚合多用户的所有 Agent 轨迹 → 识别跨用户重复模式 → 进化 Skill → 同步回全用户。",principle:'三阶段管线：结构化会话收集——用户 prompt → Agent 动作 → 中间反馈 → 最终答案，所有用户轨迹汇入同一证据池；Agentic Evolver 识别模式——自主推理引擎分析所有轨迹，识别跨用户反复出现的行为模式（如 5 个工程师独立发现"先备份 → 分块 → 合并"三步流程→提炼为 Skill）；共享仓库同步——进化后的 Skill 自动同步到所有用户的所有 Agent 实例。关键洞察：单个用户很少产生足够信号区分"可泛化改进"和"特定场景补丁"，但聚合多用户互补视角后哪些模式真正通用就变清晰。原生集成 Hermes / OpenClaw / QwenPaw 以及 OpenAI 兼容 API。',capabilities:["多用户轨迹聚合","Agentic Evolver 跨用户模式识别","共享 Skill 仓库自动同步"],limitations:["仅在 Qwen3-Max 上验证","隐私和冲突解决未详述——不同用户经验矛盾时强制合并为统一 Skill，缺乏分支或覆盖机制","企业保密场景顾虑——多用户轨迹汇聚意味着 A 的操作模式对 B 间接可见"],references:[{label:"SkillClaw 论文",url:"https://arxiv.org/abs/2604.08377"},{label:"GitHub - AMAP-ML/SkillClaw",url:"https://github.com/AMAP-ML/SkillClaw"},{label:"36kr 解析",url:"https://eu.36kr.com/en/p/3767753692201481"}]},logo:"https://raw.githubusercontent.com/AMAP-ML/SkillClaw/main/assets/skillclaw_logo.png",metrics:{stars:1308,forks:126,repo:"AMAP-ML/SkillClaw",paperDate:"2026-04"}},{id:"metaclaw",name:"MetaClaw",description:"Fast Loop（秒级 Skill）+ Slow Loop（小时级 LoRA）双环零停机进化（Kimi-K2.5 21.4% → 40.6%）",source:"OpenClaw (3.4K+ ★)",link:"https://github.com/aiming-lab/MetaClaw",detail:{tagline:"双环架构（Fast Loop 秒级 Skill 进化 + Slow Loop 小时级 LoRA 微调）实现 7×24 生产 Agent 的零停机持续进化。",principle:'Fast Loop 秒级：Agent 执行失败 → LLM Evolver 立即分析失败轨迹 → 诊断根因 → 合成新 Skill → 即时生效，零停机（例如新格式日志失败几秒内生成解析 Skill）。Slow Loop 小时级：在用户不活跃时段（凌晨 2-6 点）通过 LoRA 微调 + RL-PRM 做梯度级模型更新，OMLS 调度器监控系统不活跃状态和日历数据判断"什么时候可以安全跑训练"。双环互增强——更好模型策略产生更好执行轨迹产生更高质量 Skill 提供更好训练数据。数据版本控制分离 support（训练用）和 query（评测用）防止"用考试题训练"。Kimi-K2.5 准确率 21.4% → 40.6%，复合鲁棒性 +18.3%。',capabilities:["Fast Loop 秒级 Skill 进化零停机","Slow Loop LoRA + RL-PRM 梯度级更新","OMLS 调度器 + 数据版本控制"],limitations:["紧密绑定 OpenClaw 平台","Slow Loop 需要模型权限，闭源 API 模型无法使用","Skill 合成质量依赖 LLM Evolver 自身判断"],references:[{label:"MetaClaw 论文",url:"https://arxiv.org/abs/2603.17187"},{label:"GitHub - aiming-lab/MetaClaw",url:"https://github.com/aiming-lab/MetaClaw"}]},logo:"https://raw.githubusercontent.com/aiming-lab/MetaClaw/main/assets/new_logo2.png",metrics:{stars:3373,forks:438,repo:"aiming-lab/MetaClaw",paperDate:"2026-03"}},{id:"skillreducer",name:"SkillReducer",description:"Skill 静态压缩 + 渐进披露：48% description / 39% body 压缩，质量反升 2.8%（less-is-more）",source:"港科大等",link:"https://arxiv.org/abs/2603.29919",detail:{tagline:"在 600 个 Skill + SkillsBench 实证揭示 Skill 生态系统性冗余—— description 压缩 48% + body 压缩 39%，功能质量反升 2.8%（less-is-more 效应）。",principle:'研究样本 600 个公开 Skill + SkillsBench 任务套，发现 26.4% Skill 没写 description，body 中 60%+ 是"非可操作"内容，reference 文件注入量达数万 Token。Stage 1 路由层优化（Delta Debugging）：用对抗性方法找 description 的"最小充分子集"，逐个删除测试"Agent 还能正确找到这个 Skill 吗"，最终压缩到只留最关键的词，压缩率 48%。Stage 2 Body 重构（渐进披露）：Skill body 分层为核心规则（永远加载）和背景知识 + 示例（按需加载），Agent 默认只看"首页"，压缩率 39%。压缩后功能质量反 +2.8%——干扰 Agent 注意力的噪音少了。在四个家族五个模型上迁移有效。',capabilities:["Delta Debugging 找 description 最小充分子集","渐进披露 body 分层","压缩后质量反升 2.8%（less-is-more）"],limitations:["聚焦静态压缩（让已有 Skill 更精简），不涉及 Skill 内容进化或新 Skill 发现","压缩是通用的，不针对特定失败模式做定向优化","仍是学术论文阶段，未产品化",'未做"基于当前任务的动态按需加载"'],references:[{label:"SkillReducer 论文",url:"https://arxiv.org/abs/2603.29919"}]},metrics:{paperDate:"2026-03"}},{id:"evoskill-opt",name:"EvoSkill (Pareto)",description:"Pareto 前沿选择 + Git 分支管理每个进化变体",source:"Sentient AGI",link:"https://github.com/sentient-agi/EvoSkill",detail:{tagline:'三 Agent 协作（Executor / Proposer / Skill-Builder）从失败轨迹中自动诊断"卡在哪"并物化为 Skill。',principle:'不依赖人类作者，从失败循环中自动生长 Skill：Executor 执行任务并记录轨迹；Proposer 分析失败轨迹诊断根因（如"Agent 不知道要等 DOM 稳定再抽取"）；Skill-Builder 将诊断结果物化为结构化 Skill 文件夹。关键机制是 Pareto 前沿选择 + Git 管理——每个变体在验证集上跑分，只有所有维度都不被超越的才保留，每个变体存为独立 Git 分支。在 OfficeQA 上 +7.3%、SealQA 上 +12.1%。',capabilities:["自动失败归因","Pareto 多维选择","Skill 进化历史可追溯"],limitations:['依赖 ground-truth 信号（必须知道"对了还是错了"才能诊断）',"在开放式任务（没有明确成功标准）上受限","主要在 OfficeQA / SealQA 基准上验证"],references:[{label:"EvoSkill 论文",url:"https://arxiv.org/abs/2603.02766"},{label:"GitHub - sentient-agi/EvoSkill",url:"https://github.com/sentient-agi/EvoSkill"}]},logo:"https://raw.githubusercontent.com/sentient-agi/EvoSkill/main/assets/evoskill_logo.png",metrics:{stars:730,forks:79,repo:"sentient-agi/EvoSkill",paperDate:"2026-03"}},{id:"skillforge-opt",name:"SkillForge (Optimizer)",description:"Failure Analyzer → Diagnostician → Optimizer 端到端 Skill 重写流水线",source:"工业研究",link:"https://arxiv.org/abs/2604.08618",detail:{tagline:"工业研究的领域专属 Skill 自动化生产线——从 1,883 条历史工单挖掘工具 schema + 三阶段自优化流水线，5 个真实云技术支持场景验证（SIGIR 2026 Industry Track）。",principle:'Domain-Contextualized Skill Creator 从历史工单挖掘两类信息：工具挖掘识别专家在工单中高频使用的诊断工具提取其 schema；知识抽取从内部文档和工单引用的参考资料中提取领域规则（例如分析 1000 个"ECS 无法启动"工单发现专家 90% 时间先跑 ecs-diag → 再查 VPC 安全组 → 最后看系统日志，这个诊断路径编码为 Skill）。三阶段自优化流水线（关键创新）：Failure Analyzer 分析执行失败；Skill Diagnostician 将失败追溯到具体 Skill 缺陷；Skill Optimizer 重写 Skill 消除根因——直接将失败归因到 Skill。5 个真实云技术支持场景使用 1,883 条匿名化生产工单 + 3,737 任务验证。',capabilities:["Domain-Contextualized Skill Creator 从工单挖掘工具 + 知识","Failure Analyzer / Diagnostician / Optimizer 三阶段流水线","归因分离直接定位 Skill 缺陷"],limitations:["仅在云技术支持场景验证，通用性未知","代码和数据未开源（企业隐私）","聚焦单 Skill 优化，不涉及多 Skill 协同",'Diagnostician 只做"是否 Skill 的问题"这一层归因，不区分 Skill 内容 / 模型能力 / 路由错误'],references:[{label:"SkillForge 论文",url:"https://arxiv.org/abs/2604.08618"}]},metrics:{paperDate:"2026-04",venue:"SIGIR 2026"}},{id:"skillrl-opt",name:"SkillRL",description:"Skill 库随 RL 策略递归共进化，分层 SkillBank 持续生长",source:"aiming-lab",link:"https://github.com/aiming-lab/SkillRL",detail:{tagline:"通过经验蒸馏 + 自适应检索 + 递归共进化，让分层 SkillBank 与 RL 策略一起生长。+15.3% over baselines（ALFWorld / WebShop / 7 搜索增强任务）。",principle:"三个关键创新：经验蒸馏机制把 Agent 的成功 / 失败经验提炼为分层 SkillBank（策略层 / 操作层）；自适应检索策略同时支持通用启发式和任务特定的 Skill 召回；递归共进化机制让 Skill 库不是静态的，而是随 RL 策略一起更新——新策略发现的新模式回写为 Skill，新 Skill 又改进下次策略。在 ALFWorld、WebShop 和 7 个搜索增强任务上 +15.3%。与 EvoSkill 区别：EvoSkill 是纯 LLM-based 从失败中发现 Skill，SkillRL 是 RL-based 让 Skill 库与 RL policy 同时学习。",capabilities:["分层 SkillBank 构建","自适应 Skill 检索","与 RL 策略的递归共进化"],limitations:["需要可定义 reward 的环境，开放式任务受限","13 位作者均为学术研究，未见生产部署","RL 训练成本高于纯 LLM 路径"],references:[{label:"SkillRL 论文",url:"https://arxiv.org/abs/2602.08234"},{label:"GitHub - aiming-lab/SkillRL",url:"https://github.com/aiming-lab/SkillRL"}]},metrics:{stars:720,forks:55,repo:"aiming-lab/SkillRL",paperDate:"2026-02"}}]},{id:"management",label:"Skill 管理",label_en:"Management",color:"#B8B8B8",technologies:[{id:"skills-sh",name:"Vercel skills.sh",description:"Vercel 官方运营的 Skill 注册中心 / 排行榜，90,000+ Skill、19 个 Agent 框架支持",source:"Vercel (2026-01 上线)",link:"https://skills.sh/",detail:{tagline:"Vercel 官方运营的 Agent Skill 注册中心 + 排行榜—— 90,000+ Skill 索引，支持 19 个 Agent 框架（Claude / Codex / Cursor / Copilot / Windsurf / Gemini 等）。",principle:'skills.sh 是 2026 年 Agent Skill 生态中事实上的分发中心：索引 Skill 数 90,000+，支持 19 个 Agent 框架，上线于 2026-01-20。已发布官方 Skill 的公司包括 Vercel、Prisma、Supabase、Stripe、Coinbase、Microsoft 等——当 Stripe 给自己的 API 发布"官方 Skill"时，相当于 npm 上的官方 SDK 包，这是 Skill 生态从社区到工业的标志性转变。与 SkillNet 区别：SkillNet 是学术驱动 + Ontology 治理 + 5 维质量评分（偏研究），skills.sh 是工业级分发 + 一键安装 + 跨 Agent 兼容（偏工程）。',capabilities:["一键发现并安装 Skill","跨 19 个 Agent 框架格式适配","排行榜 / 趋势追踪"],limitations:["没有安全审计能力—— Liu et al. 2026 发现 26.1% 社区 Skill 含漏洞，但 skills.sh 没有强制安全扫描","商业产品，未开源排行榜算法","Vercel 主导，存在生态绑定风险"],references:[{label:"skills.sh 官网",url:"https://skills.sh/"},{label:"vercel-labs/skills GitHub",url:"https://github.com/vercel-labs/skills"}]},logo:"https://www.google.com/s2/favicons?domain=skills.sh&sz=128",metrics:{stars:18093,forks:1465,repo:"vercel-labs/skills"}},{id:"skillnet",name:"SkillNet",description:"200K+ Skill 集中式知识库，搜索 / 下载 / 五维评分（公共市场模式）",source:"浙大 NLP",link:"https://github.com/zjunlp/SkillNet",detail:{tagline:"把 200K+ Skill 生态组织成「应用商店基础设施」—— Ontology 三层架构 + 5 维质量评分（GitHub 735 星）。",principle:'把"Skill 生态"从无组织的 200K+ 个孤岛升级为可治理的知识图谱：Skill Ontology 三层架构——领域分类（如"数据处理""代码生成"）→ Skill 实体（200K+）→ 关系图谱（功能重叠 / 依赖 / 升级版）；5 维质量评分覆盖安全 / 完整 / 可执行 / 可维护 / 成本，超越 Star 数；在 ALFWorld / WebShop / ScienceWorld 三环境实证 +40% reward、-30% 执行步骤。业界首个面向 Skill 生态的关系治理框架，并把"Skill 内在质量"标准化。',capabilities:["Skill 自动分类、查重、关系建模","多维质量评分","在线开放知识库"],limitations:['5 维评分评估的是"Skill 写得好不好"，不是"在你的场景有没有效"',"团队自述：动态组合和跨领域迁移仍具挑战性","关系图谱能识别重叠但不执行自动合并"],references:[{label:"SkillNet 论文",url:"https://arxiv.org/abs/2603.04448"},{label:"GitHub - zjunlp/SkillNet",url:"https://github.com/zjunlp/SkillNet"},{label:"在线知识库 skillnet.openkg.cn",url:"http://skillnet.openkg.cn/"},{label:"HuggingFace 博客",url:"https://huggingface.co/blog/xzwnlp/skillnet"}]},logo:"https://raw.githubusercontent.com/zjunlp/SkillNet/main/images/skillnet.png",metrics:{stars:738,forks:72,repo:"zjunlp/SkillNet",paperDate:"2026-03"}},{id:"agentskillos",name:"AgentSkillOS",description:"生态级 Skill 组织 / 编排 / 生命周期管理（Capability Tree + DAG）",source:"学术研究",link:"https://arxiv.org/abs/2603.02176",detail:{tagline:'把数十万 Skill 组织成 Capability Tree + DAG 编排的"操作系统级"基础设施。',principle:'Capability Tree 递归分类把数十万 Skill 组织成一棵能力树：节点是能力类别，叶子是具体 Skill，用户提任务时系统从树根递归定位到最相关 Skill 子集；对比线性搜索，树状检索在 200 - 200K 规模上都接近理想准确率。DAG 编排（核心创新）识别任务中的 Skill 依赖关系构建有向无环图：能并行的步骤并行（如"抓取数据" + "准备 PPT 模板"），必须串行的按序执行，DAG 执行显著优于简单逐个调用。基准覆盖数据计算 / 文档创建 / 动态视频 / 视觉设计 / Web 交互 30 个任务。',capabilities:["Capability Tree 树状 Skill 检索","DAG 任务编排与并行执行","200-200K 规模接近理想检索准确率"],limitations:["DAG 编排假设 Skill 依赖关系可在执行前静态确定，动态依赖场景（第二步选择取决于第一步结果）未覆盖","不涉及 Skill 进化或安全治理","仅学术验证，未产品化"],references:[{label:"AgentSkillOS 论文",url:"https://arxiv.org/abs/2603.02176"}]},metrics:{paperDate:"2026-03"}},{id:"skills-standard",name:"Agent Skills 标准",description:"agentskills.io：Anthropic 发起的跨平台 Skill 开放标准，~38+ 产品采用（Claude Code / Cursor / Gemini CLI 等）",source:"开放标准（Anthropic 发起）",link:"https://agentskills.io/",detail:{tagline:'跨平台 Skill 格式与协议的开放标准——解决"同一 Skill 在不同 Agent 框架上格式互通"问题。',principle:'定义跨 Agent 平台（Claude / Gemini / OpenAI / LangChain / Cursor 等）的统一 Skill 格式与协议，让一份 Skill 文件可被所有合规框架消费。现状判断：已发布初版规范；部分工具（如 Skill Seekers）声称支持 20 个平台格式，但没有验证"转换后的 Skill 在目标平台上效果是否与源平台一致"——格式兼容 ≠ 行为一致，同一个 Skill 在 Claude Code 和 OpenCode 上即使格式兼容，执行行为也可能完全不同。',capabilities:["定义跨 Agent 平台统一 Skill 格式与协议","已被多个工具引用","促进生态互操作"],limitations:["仅是规范级别，无强制约束力","不解决跨框架的行为一致性问题（只解决格式兼容）","缺乏权威治理机构和合规测试套件"],references:[{label:"agentskills.io 官网",url:"https://agentskills.io/"}]},logo:"https://www.google.com/s2/favicons?domain=agentskills.io&sz=128"}]}],I={categories:q},J={class:"landscape-root"},Y={class:"landscape-header"},ll={class:"landscape-stats"},el={class:"landscape-grid"},il={class:"stage-header"},tl={class:"stage-icon"},al={class:"stage-title"},sl={class:"stage-count"},rl={class:"cards"},ol=["onClick"],nl={class:"logo-wrap"},cl=["src","alt","onError"],kl={class:"tech-name"},pl={class:"tech-source"},ul=["title"],Sl={class:"card-metric-icon"},gl={class:"modal-card"},dl={class:"modal-head"},ml={class:"logo-wrap large"},bl=["src","alt"],hl